# MediSafe Clinic - DSTI 자동 설치 (PowerShell)
# 실행 방법: 마우스 우클릭 -> PowerShell로 실행

$Host.UI.RawUI.WindowTitle = "MediSafe Clinic - DSTI 설치"
$ErrorActionPreference = "Stop"

Write-Host ""
Write-Host "  ╔══════════════════════════════════════════╗" -ForegroundColor Cyan
Write-Host "  ║  MediSafe Clinic - PC 보안 에이전트     ║" -ForegroundColor Cyan
Write-Host "  ║  DSTI 전용 v1.0  (자동 설치)            ║" -ForegroundColor Cyan
Write-Host "  ╚══════════════════════════════════════════╝" -ForegroundColor Cyan
Write-Host ""

# ── 설치 폴더
$INSTALL = "C:\MediSafe"
if (-not (Test-Path $INSTALL)) { New-Item -ItemType Directory -Path $INSTALL | Out-Null }
Write-Host "[1/4] 설치 폴더: $INSTALL" -ForegroundColor Green

# ── Python 확인
Write-Host "[2/4] Python 확인 중..." -ForegroundColor Yellow
try {
    $pyver = python --version 2>&1
    Write-Host "  OK: $pyver" -ForegroundColor Green
} catch {
    Write-Host "  Python 미설치. winget으로 설치합니다..." -ForegroundColor Red
    winget install -e --id Python.Python.3.12 --silent --accept-package-agreements --accept-source-agreements
    Write-Host "  설치 완료. 이 창을 닫고 다시 실행하세요." -ForegroundColor Yellow
    Read-Host "Enter 키를 누르세요"
    exit
}

# ── 라이브러리 설치
Write-Host "[3/4] 라이브러리 설치 중..." -ForegroundColor Yellow
python -m pip install -q requests psutil schedule colorama
Write-Host "  OK: 라이브러리 준비 완료" -ForegroundColor Green

# ── 파일 생성 (Base64 내장)
Write-Host "[4/4] 에이전트 파일 생성 중..." -ForegroundColor Yellow

# config.py
$b64_config_py = "U0VSVkVSX1VSTCAgICAgICAgICAgICA9ICJodHRwczovL2pudHVia3duLmdlbnNwYXJrY2xhdy5jb20iClJFR0lTVEVSX0VNQUlMICAgICAgICAgPSAiaHRraW1AZHN0aS5jby5rciIKUkVHSVNURVJfUEFTU1dPUkQgICAgICA9ICJEc3RpQEFkbWluMSEiClBDX0xPQ0FUSU9OICAgICAgICAgICAgPSAiRFNUSSDsgqzrrLTsi6QiCkhFQVJUQkVBVF9JTlRFUlZBTF9NSU4gPSA1Cg=="
[System.IO.File]::WriteAllBytes("C:\MediSafe\config.py", [System.Convert]::FromBase64String($b64_config_py))
Write-Host "  OK: config.py" -ForegroundColor Green

# agent.py
$b64_agent_py = ""
[System.IO.File]::WriteAllBytes("C:\MediSafe\agent.py", [System.Convert]::FromBase64String($b64_agent_py))
Write-Host "  OK: agent.py" -ForegroundColor Green

# api_client.py
$b64_api_client_py = ""
[System.IO.File]::WriteAllBytes("C:\MediSafe\api_client.py", [System.Convert]::FromBase64String($b64_api_client_py))
Write-Host "  OK: api_client.py" -ForegroundColor Green

# collector.py
$b64_collector_py = ""
[System.IO.File]::WriteAllBytes("C:\MediSafe\collector.py", [System.Convert]::FromBase64String($b64_collector_py))
Write-Host "  OK: collector.py" -ForegroundColor Green

Write-Host ""
Write-Host "══════════════════════════════════════════════" -ForegroundColor Cyan
Write-Host "파일 생성 완료. 서버 연결 테스트 시작..." -ForegroundColor Cyan
Write-Host "══════════════════════════════════════════════" -ForegroundColor Cyan
Write-Host ""

# ── 서버 연결 테스트
Set-Location $INSTALL
python C:\MediSafe\agent.py --test

if ($LASTEXITCODE -eq 0) {
    Write-Host ""
    Write-Host "══════════════════════════════════════════════" -ForegroundColor Green
    Write-Host " 설치 완료!" -ForegroundColor Green
    Write-Host " 대시보드: https://jntubkwn.gensparkclaw.com" -ForegroundColor Green
    Write-Host " 로그인: htkim@dsti.co.kr / Dsti@Admin1!" -ForegroundColor Green
    Write-Host "══════════════════════════════════════════════" -ForegroundColor Green
    Write-Host ""

    # ── 시작 프로그램 등록
    $ans = Read-Host "PC 시작 시 자동 실행 등록? (Y/N)"
    if ($ans -eq "Y" -or $ans -eq "y") {
        $startupPath = "$env:APPDATA\Microsoft\Windows\Start Menu\Programs\Startup\MediSafe_Agent.bat"
        "@echo off`ncd /d C:\MediSafe`npython C:\MediSafe\agent.py" | Out-File -FilePath $startupPath -Encoding ascii
        Write-Host "  OK: 시작 프로그램 등록 완료" -ForegroundColor Green
    }

    Write-Host ""
    Write-Host "5분마다 자동 전송 시작합니다. (종료: 창 닫기)" -ForegroundColor Cyan
    Write-Host ""
    python C:\MediSafe\agent.py
} else {
    Write-Host ""
    Write-Host "[오류] 서버 연결 실패." -ForegroundColor Red
    Write-Host "인터넷 연결 및 방화벽(443포트)을 확인하세요." -ForegroundColor Red
}

Read-Host "종료하려면 Enter 키를 누르세요"